def _map_section_to_node(section: str, policy: dict, fallback: str = "setup_environment") -> str:
    m = (policy or {}).get("section_to_node", {})
    return m.get(section, fallback)

def _unique(seq):
    seen = set(); out = []
    for x in seq:
        if x not in seen:
            seen.add(x); out.append(x)
    return out

def _toposort_no_cycle(nodes, edges):
    adj = defaultdict(set)
    indeg = {n: 0 for n in nodes}
    for u, v in edges:
        if u == v: 
            continue
        if v not in adj[u]:
            adj[u].add(v)
            indeg[v] = indeg.get(v, 0) + 1
            indeg.setdefault(u, 0)
    q = deque([n for n in nodes if indeg.get(n, 0) == 0])
    order = []
    while q:
        u = q.popleft()
        order.append(u)
        for w in list(adj[u]):
            adj[u].remove(w)
            indeg[w] -= 1
            if indeg[w] == 0:
                q.append(w)
    # Si pas tous traités, on coupe les dernières arêtes restantes
    if len(order) < len(nodes):
        remaining = set(nodes) - set(order)
        order.extend(sorted(remaining))
    return order, [[u, v] for u in nodes for v in nodes if False]  # edges non utilisés ici

def _acyclicize(nodes, edges, node_order_hint=None):
    # Déduplique et retire self-loops
    node_set = set(nodes)
    dedup = []
    seen = set()
    for u, v in edges:
        if u == v or u not in node_set or v not in node_set:
            continue
        if (u, v) not in seen:
            seen.add((u, v))
            dedup.append([u, v])
    edges = dedup

    # Si un hint est fourni, on filtre les arêtes qui vont à l’envers
    if node_order_hint:
        pos = {n: i for i, n in enumerate(node_order_hint)}
        edges = [e for e in edges if pos.get(e[0], 9999) < pos.get(e[1], 9999)]

    # Toposort final (casse les cycles restants via ordre lexical)
    # On garde uniquement les arêtes qui respectent l’ordre toposort lexical
    lex = sorted(nodes)
    pos = {n: i for i, n in enumerate(lex)}
    edges = [[u, v] for u, v in edges if pos[u] < pos[v]]

    order, _ = _toposort_no_cycle(nodes, edges)
    return order, edges

def build_scenario_graph_from_analysis(analysis: dict, ia_policy: dict | None = None) -> dict:
    sections   = list(analysis.get("sections", []))
    priorities = analysis.get("priorities", {}) or {}
    deps       = analysis.get("dependencies", {}) or {}

    # 1) Nœuds dérivés via policy
    nodes = _unique(_map_section_to_node(s, ia_policy) for s in sections) or ["setup_environment"]

    # 2) Arêtes depuis dependencies (sections -> sections -> nodes)
    edges = []
    seen = set()
    for sink_sec, src_secs in deps.items():
        sink_node = _map_section_to_node(sink_sec, ia_policy)
        for src_sec in src_secs or []:
            src_node = _map_section_to_node(src_sec, ia_policy)
            if src_node != sink_node and (src_node, sink_node) not in seen:
                seen.add((src_node, sink_node))
                edges.append([src_node, sink_node])

    # 3) Arêtes depuis priorities (ordre de sections -> ordre de nœuds)
    if priorities:
        ordered_secs  = [k for k, _ in sorted(priorities.items(), key=lambda kv: kv[1])]
        ordered_nodes = _unique(_map_section_to_node(s, ia_policy) for s in ordered_secs)
        for i in range(len(ordered_nodes) - 1):
            u, v = ordered_nodes[i], ordered_nodes[i+1]
            if u != v and (u, v) not in seen:
                seen.add((u, v)); edges.append([u, v])

    # 4) Acyclic + ordre final
    node_order_hint = (ia_policy or {}).get("node_order_hint")
    nodes_final, edges_final = _acyclicize(nodes, edges, node_order_hint=node_order_hint)

    return {"nodes": nodes_final, "edges": edges_final}

