from dotenv import load_dotenv
load_dotenv()

def choose(options, objectif=None, contraintes=None, use_ai=False):
    if not options:
        return {"choix": None, "justification": {"raison": "Liste vide"}}

    contraintes = contraintes or {}

    if use_ai:
        try:
            import openai
            import os
            from dotenv import load_dotenv
            load_dotenv()
            openai.api_key = os.getenv("OPENAI_API_KEY")

            prompt = f"""Tu es un assistant qui aide à faire des choix éclairés.
Objectif : {objectif}
Contraintes : {contraintes}
Options :
{json.dumps(options, indent=2, ensure_ascii=False)}

Indique uniquement le meilleur choix, en expliquant brièvement pourquoi.
Format JSON strict :
{{
  "choix": <option choisie>,
  "justification": "<texte explicatif>"
}}"""

            client = openai.OpenAI(api_key=os.getenv("OPENAI_API_KEY"))
            response = client.chat.completions.create(
                model="gpt-4",
                messages=[{"role": "user", "content": prompt}],
                temperature=0.3,
                max_tokens=200  # 👈 tu peux même descendre à 100 pour test rapide
            )

            content = response.choices[0].message.content

            parsed = json.loads(content)
            return parsed

        except Exception as e:
            return {
                "choix": None,
                "justification": {
                    "raison": "Erreur lors de l’appel IA",
                    "erreur": str(e),
                    "fallback": "utilisation de la logique interne"
                }
            }

    # fallback logique pondérée
    eviter = contraintes.get("éviter", [])
    if all(isinstance(opt, str) for opt in options):
        filtered = [opt for opt in options if opt not in eviter]
        choix = filtered[0] if filtered else options[0]
        return {
            "choix": choix,
            "justification": {
                "raison": "Choix pondéré par exclusion",
                "objectif": objectif,
                "contraintes": contraintes
            }
        }

    def score(opt):
        s = 0
        for k, v in contraintes.items():
            if isinstance(opt, dict) and k in opt and opt[k] not in v:
                s += 1
        return s

    best = sorted(options, key=score, reverse=True)[0]
    return {
